      a.str_value,
      (CASE WHEN a.num_value1=-999 THEN NULL  ELSE a.num_value1 END )::numeric  AS num_value1,
      (CASE WHEN a.num_value2=-999 THEN NULL  ELSE a.num_value2 END )::numeric  AS num_value2,
